/* ── Matrix Rain ── */
function MatrixRain() {
  const ref = useRef(null);
  useEffect(() => {
    const canvas = ref.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    let W, H, cols, drops;
    const chars = "アイウエオ01ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789{}[]<>/|;:";
    function init() {
      W = canvas.width = window.innerWidth;
      H = canvas.height = window.innerHeight;
      cols = Math.floor(W / 20);
      drops = Array(cols).fill(1);
    }
    init();
    function draw() {
      ctx.fillStyle = "rgba(0,0,0,0.04)";
      ctx.fillRect(0, 0, W, H);
      ctx.font = "14px monospace";
      drops.forEach((y, i) => {
        const c = chars[Math.floor(Math.random() * chars.length)];
        ctx.globalAlpha = Math.random() > 0.97 ? 0.8 : 0.28;
        ctx.fillStyle = "#00ff41";
        ctx.fillText(c, i * 20, y * 20);
        ctx.globalAlpha = 1;
        if (y * 20 > H && Math.random() > 0.975) drops[i] = 0;
        drops[i]++;
      });
    }
    const id = setInterval(draw, 50);
    window.addEventListener("resize", init);
    return () => { clearInterval(id); window.removeEventListener("resize", init); };
  }, []);
  return (
    <canvas ref={ref} style={{
      position: "fixed", top: 0, left: 0, width: "100%", height: "100%",
      zIndex: 0, opacity: 0.14, pointerEvents: "none"
    }} />
  );
}

/* ── Loading Screen ── */
function LoadingScreen({ onDone }) {
  const [count, setCount] = useState(0);
  const [done, setDone] = useState(false);

  useEffect(() => {
    if (count >= BOOT_LINES.length) {
      const t = setTimeout(() => { setDone(true); onDone(); }, 600);
      return () => clearTimeout(t);
    }
    const t = setTimeout(() => setCount(c => c + 1), 300);
    return () => clearTimeout(t);
  }, [count]);

  const pct = Math.round((count / BOOT_LINES.length) * 100);
  const visible = BOOT_LINES.slice(0, count);

  return (
    <div style={{ position: "fixed", inset: 0, background: "#000", zIndex: 9999,
      display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 24 }}>
      <div style={{ fontSize: "clamp(20px,4vw,34px)", color: "#00ff41", letterSpacing: 4,
        marginBottom: 32, textShadow: "0 0 20px #00ff41", fontFamily: "'Orbitron',monospace", fontWeight: 700 }}>
        [SYSTEM BOOT]
      </div>
      <div style={{ width: "min(500px,92vw)", background: "rgba(0,255,65,0.03)",
        border: "1px solid #00ff4133", borderRadius: 8, padding: 24, minHeight: 160 }}>
        {visible.map((line, i) => (
          <div key={i} style={{
            color: line && line.includes("GRANTED") ? "#00ffff" : "#00ff41",
            fontSize: 13, marginBottom: 6
          }}>
            {line}
            {i === visible.length - 1 && (
              <span style={{ animation: "blink 1s step-end infinite" }}>_</span>
            )}
          </div>
        ))}
      </div>
      <div style={{ marginTop: 24, width: "min(500px,92vw)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", color: "#00ff41", fontSize: 12, marginBottom: 6 }}>
          <span>Loading portfolio...</span><span>{pct}%</span>
        </div>
        <div style={{ background: "#0a0a0a", border: "1px solid #00ff4144", borderRadius: 4, height: 6 }}>
          <div style={{ height: "100%", background: "linear-gradient(90deg,#00ff41,#00ffff)",
            borderRadius: 4, width: `${pct}%`, transition: "width 0.3s", boxShadow: "0 0 8px #00ff41" }} />
        </div>
      </div>
    </div>
  );
}

