/* ── Typing Effect ── */
function Typing({ phrases }) {
  const [text, setText] = useState("");
  const [pi, setPi] = useState(0);
  const [del, setDel] = useState(false);
  useEffect(() => {
    const phrase = phrases[pi] || "";
    const t = setTimeout(() => {
      if (!del) {
        if (text.length < phrase.length) setText(phrase.slice(0, text.length + 1));
        else setTimeout(() => setDel(true), 1800);
      } else {
        if (text.length > 0) setText(text.slice(0, -1));
        else { setDel(false); setPi(p => (p + 1) % phrases.length); }
      }
    }, del ? 40 : 80);
    return () => clearTimeout(t);
  }, [text, del, pi, phrases]);
  return (
    <span style={{ color: "#00ffff", textShadow: "0 0 12px #00ffff" }}>
      {text}
      <span style={{ animation: "blink 1s step-end infinite", color: "#00ff41" }}>|</span>
    </span>
  );
}

