/* ── Progress Bar ── */
function ProgressBar({ label, pct, color = "#00ff41" }) {
  const [w, setW] = useState(0);
  const ref = useRef(null);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) setTimeout(() => setW(pct), 100);
    }, { threshold: 0.3 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [pct]);
  return (
    <div ref={ref} style={{ marginBottom: 14 }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 5 }}>
        <span style={{ color: "#ccc", fontSize: 12 }}>{label}</span>
        <span style={{ color, fontSize: 11 }}>{pct}%</span>
      </div>
      <div style={{ background: "#0d0d0d", border: "1px solid #ffffff0f", borderRadius: 4, height: 5, overflow: "hidden" }}>
        <div style={{ height: "100%", width: `${w}%`,
          background: `linear-gradient(90deg,${color},${color}99)`,
          borderRadius: 4, transition: "width 1.2s cubic-bezier(0.4,0,0.2,1)",
          boxShadow: `0 0 6px ${color}` }} />
      </div>
    </div>
  );
}

