/* ── Animated hex ring around photo ── */
function HexPhoto() {
  const [ang, setAng] = useState(0);
  useEffect(() => {
    const id = setInterval(() => setAng(a => (a + 0.4) % 360), 16);
    return () => clearInterval(id);
  }, []);
  const size = 220;
  const r = size / 2;
  return (
    <div style={{ position: "relative", width: size, height: size, flexShrink: 0 }}>
      {/* Rotating outer ring */}
      <svg width={size} height={size} style={{ position: "absolute", top: 0, left: 0 }}>
        <defs>
          <linearGradient id="ringGrad" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#00ff41" stopOpacity="1" />
            <stop offset="50%" stopColor="#00ffff" stopOpacity="0.6" />
            <stop offset="100%" stopColor="#00ff41" stopOpacity="0.1" />
          </linearGradient>
        </defs>
        <circle cx={r} cy={r} r={r - 4} fill="none" stroke="url(#ringGrad)"
          strokeWidth="2" strokeDasharray="18 6"
          transform={`rotate(${ang} ${r} ${r})`} />
        <circle cx={r} cy={r} r={r - 12} fill="none" stroke="#00ff4122" strokeWidth="1" />
        {/* Corner tick marks */}
        {[0,60,120,180,240,300].map(deg => {
          const rad = (deg * Math.PI) / 180;
          const x1 = r + (r-8) * Math.cos(rad);
          const y1 = r + (r-8) * Math.sin(rad);
          const x2 = r + (r-18) * Math.cos(rad);
          const y2 = r + (r-18) * Math.sin(rad);
          return <line key={deg} x1={x1} y1={y1} x2={x2} y2={y2} stroke="#00ff41" strokeWidth="2" opacity="0.7" />;
        })}
      </svg>
      {/* Glow backdrop */}
      <div style={{ position: "absolute", inset: 12, borderRadius: "50%",
        background: "radial-gradient(circle,#00ff4118 0%,transparent 70%)",
        boxShadow: "0 0 40px #00ff4133, inset 0 0 30px #00ff4111" }} />
      {/* Photo */}
      <div style={{ position: "absolute", inset: 14, borderRadius: "50%", overflow: "hidden",
        border: "2px solid #00ff4166",
        boxShadow: "0 0 20px #00ff4144, 0 0 60px #00ff4122" }}>
        <img src={PROFILE_PHOTO} alt="Yashraj Bhore"
          style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: "center top" }} />
      </div>
      {/* Status dot */}
      <div style={{ position: "absolute", bottom: 18, right: 18, width: 14, height: 14,
        borderRadius: "50%", background: "#00ff41", border: "2px solid #000",
        boxShadow: "0 0 8px #00ff41" }} />
    </div>
  );
}

