function Contact() {
  const [form, setForm] = useState({ name:"", email:"", message:"" });
  const [sent, setSent] = useState(false);
  const iStyle = {
    background: "rgba(0,255,65,0.04)", border: "1px solid #00ff4133", borderRadius: 8,
    color: "#fff", padding: "11px 14px", width: "100%", fontSize: 13, outline: "none",
    fontFamily: "'Courier New',monospace", transition: "border-color 0.2s"
  };
  return (
    <S id="contact" bg="rgba(0,255,65,0.008)">
      <SectionTitle sub="Get In Touch">CONTACT</SectionTitle>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(260px,1fr))", gap: 28 }}>
        <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
          {[
            { icon:"📧", label:"Email",    val:"yashrajbhore07@gmail.com",    href:"mailto:yashrajbhore07@gmail.com" },
            { icon:"📱", label:"Phone",    val:"+91 9021008250",              href:"tel:+919021008250" },
            { icon:"🔗", label:"LinkedIn", val:"linkedin.com/in/yashrajbhore",href:"https://linkedin.com/in/yashrajbhore" },
            { icon:"⌨",  label:"GitHub",   val:"github.com/yashrajbhore07",   href:"https://github.com/yashrajbhore07" },
          ].map(({ icon, label, val, href }) => (
            <GlassCard key={label} style={{ padding: 16 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <span style={{ fontSize: 22 }}>{icon}</span>
                <div>
                  <div style={{ color: "#444", fontSize: 10, fontFamily: "'Orbitron',monospace", letterSpacing: 1 }}>{label}</div>
                  <a href={href} target="_blank" rel="noopener noreferrer"
                    style={{ color: "#00ff41", fontSize: 12, textDecoration: "none" }}>{val}</a>
                </div>
              </div>
            </GlassCard>
          ))}
        </div>
        <GlassCard style={{ padding: 24 }}>
          {sent ? (
            <div style={{ textAlign: "center", padding: 40 }}>
              <div style={{ fontSize: 44, marginBottom: 14 }}>✅</div>
              <div style={{ fontFamily: "'Orbitron',monospace", color: "#00ff41", fontSize: 15 }}>MESSAGE SENT</div>
              <div style={{ color: "#555", marginTop: 8, fontSize: 12 }}>I'll get back to you shortly.</div>
            </div>
          ) : (
            <>
              <div style={{ fontFamily: "'Orbitron',monospace", color: "#00ff41", fontSize: 11, letterSpacing: 2, marginBottom: 18 }}>
                // SEND MESSAGE
              </div>
              {[["name","Name","text","Your name..."],["email","Email","email","your@email.com"]].map(([k,l,t,p]) => (
                <div key={k} style={{ marginBottom: 14 }}>
                  <label style={{ color: "#444", fontSize: 10, fontFamily: "'Orbitron',monospace",
                    letterSpacing: 1, display: "block", marginBottom: 5 }}>{l}</label>
                  <input type={t} placeholder={p} value={form[k]}
                    onChange={e => setForm(f => ({ ...f, [k]: e.target.value }))}
                    style={iStyle}
                    onFocus={e => { e.target.style.borderColor="#00ff41"; e.target.style.boxShadow="0 0 8px #00ff4133"; }}
                    onBlur={e =>  { e.target.style.borderColor="#00ff4133"; e.target.style.boxShadow="none"; }} />
                </div>
              ))}
              <div style={{ marginBottom: 18 }}>
                <label style={{ color: "#444", fontSize: 10, fontFamily: "'Orbitron',monospace",
                  letterSpacing: 1, display: "block", marginBottom: 5 }}>Message</label>
                <textarea rows={4} placeholder="Write your message here..." value={form.message}
                  onChange={e => setForm(f => ({ ...f, message: e.target.value }))}
                  style={{ ...iStyle, resize: "vertical" }}
                  onFocus={e => { e.target.style.borderColor="#00ff41"; e.target.style.boxShadow="0 0 8px #00ff4133"; }}
                  onBlur={e =>  { e.target.style.borderColor="#00ff4133"; e.target.style.boxShadow="none"; }} />
              </div>
              <button
                onClick={() => { if (form.name && form.email && form.message) setSent(true); }}
                style={{ width: "100%", padding: 12, background: "linear-gradient(135deg,#00ff41,#00cc33)",
                  border: "none", borderRadius: 8, color: "#000", fontFamily: "'Orbitron',monospace",
                  fontSize: 12, letterSpacing: 2, cursor: "pointer", fontWeight: 700, boxShadow: "0 0 16px #00ff4144" }}>
                SEND MESSAGE
              </button>
            </>
          )}
        </GlassCard>
      </div>
    </S>
  );
}

